;
; Static decorations. Type is a catalog id (catalog/decorations.cat).
; Format: decoration <type> <x> <z> [facing] [key=value]. All props block the
; party except open passages (add solid=0); authored imports (ancient_pot/
; boulder/mossy_rock/pot/banner) carry their own texture set.
;
; Start room
; (The fab.com weapons that used to stand here as a showcase are now pickable
; item entities just ahead of the spawn — see level1.ent.)
decoration ancient_pot 2 2 south
decoration barrel 7 6 south
decoration rope 6 4 south
; Portcullis gating the 1-wide corridor south out of the start room (the room
; also opens east, so this doesn't block progress).
decoration portcullis 4 7 north
; Stairs down to level 2 (arrive next to level2's start). Placed in the pillared
; hall (out of the start room so the start floor stays clear).
stairs stairs_down 18 4 south dest=level2 destx=2 destz=1
;
; Great pillared hall — the NW corner carries two sconces, one per wall, and
; the NE corner a sconce plus a wall banner on the other wall: several wall
; fixtures/decorations sharing one square.
fixture sconce 11 2 north
fixture sconce 11 2 west
fixture sconce 21 2 north
decoration banner 21 2 wall=east
decoration column_marble 12 3 south
decoration column_marble 20 3 south
decoration column_marble 12 8 south
decoration column_marble 20 8 south
decoration statue_marble 16 2 south
decoration archway 10 4 east solid=0
;
; Fountain hall (dusty)
decoration fountain 14 15 south
decoration column 12 12 south
decoration column 19 12 south
decoration ancient_pot 12 18 south
decoration pot 18 18 south
decoration archway 16 11 south solid=0
;
; West crypt
decoration statue 6 10 south
decoration chest 2 15 south
decoration ancient_pot 6 14 south
decoration mossy_rock 3 12 east solid=0
;
; NE chamber (storage)
decoration chest 25 2 south
decoration barrel 29 2 south
decoration crate 28 6 south
;
; East gallery
decoration column 25 10 south
decoration column 29 15 south
decoration statue 28 9 south
;
; SW cavern (dusty rubble)
decoration boulder 4 21 east solid=0
decoration boulder 8 23 south solid=0
decoration mossy_rock 7 27 south solid=0
decoration pot 3 28 south
;
; South treasure vault
decoration chest 15 23 south
decoration chest 21 29 south
decoration barrel 16 28 south
decoration crate 20 24 south
decoration statue 18 23 south
decoration iron_door 16 23 north solid=0
;
; SE chamber
decoration crate 29 20 south
decoration barrel 25 29 south
decoration pot 27 22 south
